export function isSingleValue(x) {
    return x === true || typeof x === "string";
}
export const Nothing = {};
export function Just(x) { return { Just: x }; }
export function isJust(x) { return "Just" in x; }
export function Left(x) { return { Left: x }; }
export function Right(x) { return { Right: x }; }
export function isLeft(x) { return "Left" in x; }
export function isRight(x) { return "Right" in x; }
export function fromEither(fl, fr, x) {
    return isLeft(x) ? fl(x.Left) : fr(x.Right);
}
export function mapEither(f, e) {
    return isLeft(e) ? Left(e.Left) : Right(f(e.Right));
}
